cardCss:
/*
 * OBON FESTIVAL
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Japanese ancestor festival — paper lanterns glowing on dark
 *             water, warm orange-red light, reflections, brush calligraphy
 * Fonts     : Noto Serif JP (heavy weight) — brush calligraphy gravitas
 * Palette   : deep water #040810 · lantern amber #e8920a · red #c03010
 *             reflection shimmer #f8d080
 * Background: near-black deep water + radial-gradient amber lantern pools
 * Lanterns  : CSS-drawn ellipses with SVG feGaussianBlur + feBlend screen glow
 * Reflection: SVG feTurbulence (turbulence, 0.015) → feDisplacementMap (scale 8)
 *             with animated baseFrequency for gentle water ripple — applied to
 *             the bottom half reflection zone only
 * Typography: vertical writing (writing-mode: vertical-rl) on front; horizontal back
 */

@import url("https://fonts.googleapis.com/css2?family=Noto+Serif+JP:wght@400;700;900&display=swap");

:root {
  --ob-water:  #040810;
  --ob-amber:  #e8920a;
  --ob-red:    #c03010;
  --ob-shimmer:#f8d080;
  --ob-text:   #f0d8b0;
}

html, body, div#qa { height: 100%; }

.card { background: var(--ob-water); min-height: 100%; }

.off-screen { position: absolute; left: -9999px; }

.ob-card {
  min-height: 100%;
  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  overflow: hidden;
  box-sizing: border-box;
  background: var(--ob-water);
}

/* ── WATER RIPPLE ZONE ── */
.ob-water-layer {
  position: absolute;
  bottom: 0;
  left: 0; right: 0;
  height: 45%;
  background: linear-gradient(to bottom, transparent, rgba(232,146,10,0.06));
  filter: url(#ob-ripple);
  pointer-events: none;
  z-index: 0;
}

/* ── LANTERNS ── */
.ob-lantern {
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  z-index: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
}

.ob-lantern--top { top: 0.5rem; }
.ob-lantern--bottom { bottom: -1.5rem; }

.ob-lantern-glow {
  width: 3.5rem;
  height: 4rem;
  background: radial-gradient(ellipse at 50% 40%, #f8c060 0%, #e8920a 40%, #a05008 70%, transparent 100%);
  border-radius: 50% 50% 45% 45%;
  box-shadow:
    0 0 20px 10px rgba(232,146,10,0.4),
    0 0 60px 20px rgba(232,146,10,0.15);
  filter: url(#ob-glow);
}

/* Front lanterns: dim, mysterious */
.ob-front .ob-lantern-glow {
  background: radial-gradient(ellipse at 50% 40%, rgba(248,192,96,0.45) 0%, rgba(232,146,10,0.3) 40%, transparent 75%);
  box-shadow:
    0 0 10px 4px rgba(232,146,10,0.2),
    0 0 28px 8px rgba(232,146,10,0.07);
  filter: url(#ob-glow);
  opacity: 0.6;
}

/* Back lanterns: bright, warm — the answer is revealed */
.ob-back .ob-lantern-glow {
  background: radial-gradient(ellipse at 50% 40%, #fff0a0 0%, #f8c060 25%, #e8920a 50%, #a05008 75%, transparent 100%);
  box-shadow:
    0 0 30px 15px rgba(232,146,10,0.65),
    0 0 80px 30px rgba(232,146,10,0.3),
    0 0 120px 50px rgba(232,146,10,0.1);
  filter: url(#ob-glow);
  opacity: 1;
}

/* ── CONTENT ── */
.ob-content {
  position: relative;
  z-index: 2;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 5rem 2rem 7rem;
  width: 100%;
  box-sizing: border-box;
}

.ob-vertical-text {
  display: flex;
  flex-direction: row;
  justify-content: center;
  gap: 1rem;
  margin-bottom: 1.5rem;
}

.ob-prompt-vertical {
  font-family: "Noto Serif JP", serif;
  font-size: 1.8rem;
  font-weight: 900;
  color: var(--ob-amber);
  writing-mode: vertical-rl;
  text-orientation: mixed;
  text-shadow:
    0 0 12px rgba(232,146,10,0.6),
    0 0 30px rgba(232,146,10,0.2);
  margin: 0;
  letter-spacing: 0.1em;
}

.ob-sub-prompt {
  font-family: "Noto Serif JP", serif;
  font-size: 0.85rem;
  color: var(--ob-text);
  opacity: 0.5;
  writing-mode: vertical-rl;
  margin: 0;
  letter-spacing: 0.08em;
}

.ob-input-wrap { width: 100%; max-width: 22rem; }
.ob-input-wrap input {
  font-family: "Noto Serif JP", serif;
  font-size: 1.1rem;
  background: rgba(255,255,255,0.06);
  border: none;
  border-bottom: 1px solid rgba(232,146,10,0.4);
  color: var(--ob-text);
  width: 100%;
  padding: 0.4rem 0;
  text-align: center;
  letter-spacing: 0.05em;
  box-sizing: border-box;
}
.ob-input-wrap input:focus { outline: none; border-bottom-color: var(--ob-amber); }

.ob-hint-wrap { margin-top: 0.8rem; }
.ob-hint-link { font-family: "Noto Serif JP", serif; font-size: 0.85rem; color: rgba(232,146,10,0.45); text-decoration: underline; }
.ob-hint-text { font-family: "Noto Serif JP", serif; font-size: 1rem; color: var(--ob-text); opacity: 0.6; margin-top: 0.4rem; }
.ob-audio { margin: 0 0 1rem; }

/* ── BACK ── */
.ob-term {
  font-family: "Noto Serif JP", serif;
  font-size: 3.5rem;
  font-weight: 900;
  color: var(--ob-shimmer);
  text-shadow: 0 0 20px rgba(248,208,128,0.4), 0 0 50px rgba(232,146,10,0.15);
  margin: 0 0 0.5rem;
  line-height: 1.2;
}

.ob-reading { font-family: "Noto Serif JP", serif; font-size: 1.8rem; color: var(--ob-amber); margin: 0 0 0.3rem; }
.ob-translation { font-family: "Noto Serif JP", serif; font-size: 1.3rem; color: var(--ob-text); opacity: 0.85; margin: 0 0 0.2rem; }
.ob-transliteration { font-family: "Noto Serif JP", serif; font-size: 1.1rem; color: var(--ob-text); opacity: 0.55; font-style: italic; margin: 0; }
.ob-tags { font-family: "Noto Serif JP", serif; font-size: 0.9rem; color: var(--ob-amber); opacity: 0.4; margin: 0.5rem 0 0; }
.ob-rule { border: none; border-top: 1px solid rgba(232,146,10,0.25); margin: 0.8rem auto; width: 60%; }

.ob-picture img {
  max-width: 100%;
  max-height: 12rem;
  object-fit: contain;
  filter: sepia(0.4) brightness(0.7) saturate(0.8);
  margin-top: 1rem;
}

.append-play-btn-text a::after { content: "▶"; color: var(--ob-amber); }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-size: 2rem; cursor: pointer; }
